/**
 * MedX icons theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Icon size tokens and stroke widths.
 */
const ICONS_TOKENS = Object.freeze({
  primary: { value: "theme-icons-primary", scope: "theme" },
  secondary: { value: "theme-icons-secondary", scope: "theme" },
  muted: { value: "theme-icons-muted", scope: "theme" },
  accent: { value: "theme-icons-accent", scope: "theme" },
  surface: { value: "theme-icons-surface", scope: "theme" },
});

const ICONS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ICONS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const iconsRegistry = new Map();
const ICONS_listeners = new Set();
let ICONS_seq = 0;

function createIconsId(prefix = "medx-theme-icons") {
  ICONS_seq += 1;
  return `${prefix}-${ICONS_seq}`;
}

function registerIcons(config = {}) {
  const entryId = config.id ?? createIconsId();
  const preset = ICONS_PRESETS[config.preset ?? "default"] ?? ICONS_PRESETS.default;
  const token = ICONS_TOKENS[config.token ?? preset.token] ?? ICONS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ICONS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  iconsRegistry.set(entryId, entry);
  notifyIconsListeners("register", entry);
  return entry;
}

function updateIcons(id, patch = {}) {
  const entry = iconsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyIconsListeners("update", entry);
  return entry;
}

function resolveIcons(id) {
  const entry = iconsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listIconsEntries(filter = {}) {
  let items = Array.from(iconsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onIconsEvent(listener) {
  ICONS_listeners.add(listener);
  return () => ICONS_listeners.delete(listener);
}

function notifyIconsListeners(type, entry) {
  for (const listener of ICONS_listeners) {
    try {
      listener({ type, entry, registrySize: iconsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:icons] listener error", err.message);
    }
  }
}

function getIconsMetrics() {
  const items = listIconsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ICONS_TOKENS).length,
    presets: Object.keys(ICONS_PRESETS).length,
  };
}

async function runMedxIcons() {
  console.log("[medx:ui:theme:icons] runtime initialized");
  console.log(`[medx:ui:theme:icons] tokens=${Object.keys(ICONS_TOKENS).length} presets=${Object.keys(ICONS_PRESETS).length}`);

  const events = [];
  onIconsEvent((e) => events.push(e.type));

  const domains = Object.keys(ICONS_SUPPLY_CHAIN);
  const presets = Object.keys(ICONS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerIcons({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/icons" },
    });
  }

  const first = listIconsEntries()[0];
  if (first) updateIcons(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getIconsMetrics();
  const resolved = first ? resolveIcons(first.id) : null;

  console.log(`[medx:ui:theme:icons] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:icons] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:icons] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:icons] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:icons] bootstrap complete");
}

module.exports = runMedxIcons;
